updated: 2026-03-13T19:49
---
<%*
// Add task to today's daily note
// Usage: Assign to a Templater hotkey or command
const taskDescription = await tp.system.prompt("Task description:");

if (!taskDescription) {
    return; // Exit if no input
}

// Get current time
const currentTime = tp.date.now("HH:mm");

// Create task line
const taskLine = `- [ ] ${taskDescription}`;

// Create log heading
const logHeading = `### :: ${taskDescription} ::\n\n`;

// Get current file content
const file = tp.file.find_tfile(tp.file.path(true));
let content = await app.vault.read(file);

// Find and insert task after "## tasks"
const tasksRegex = /(## tasks\n)/;
if (tasksRegex.test(content)) {
    content = content.replace(tasksRegex, `$1${taskLine}\n`);
}

// Find and insert log heading after "## log"
const logRegex = /(## log\n)/;
if (logRegex.test(content)) {
    content = content.replace(logRegex, `$1\n${logHeading}`);
}

// Write updated content
await app.vault.modify(file, content);

// Move cursor to the new log section (after the heading we just created)
const lines = content.split('\n');
const logSectionIndex = lines.findIndex(line => line.includes(`:: ${taskDescription} ::`));
if (logSectionIndex !== -1) {
    // Position cursor right after the heading
    tp.file.cursor(logSectionIndex + 2, 0);
}
_%>

